// Salva o payload do ESP32 no contexto do fluxo
// para ser combinado com o clima no próximo passo
flow.set('esp32_payload', msg.payload);
return msg;

// Recupera o payload do ESP32 salvo no step anterior
// e combina com a resposta da OpenWeather
const esp32 = flow.get('esp32_payload');
const clima  = msg.payload;

if (!esp32) {
    node.warn('Payload ESP32 não encontrado no contexto. Descartando.');
    return null;
}

msg.payload = { esp32, clima };
return msg;

// === COLE AQUI O CONTEÚDO DE function_processa_telemetria.js ===
// (O arquivo completo está em /nodered/function_processa_telemetria.js)
// O código está separado para facilitar versionamento no Git.

// Stub resumido para o flow.json (substitua pelo conteúdo completo):
const esp32 = msg.payload.esp32;
const clima  = msg.payload.clima;
if (!esp32) return null;

const temp        = parseFloat(esp32.temperatura);
const umid        = parseFloat(esp32.umidade);
const ldrADC      = parseInt(esp32.ldr_adc);
const portaAberta = Boolean(esp32.porta_aberta);
const dentroFaixa = (temp >= 2.0 && temp <= 8.0);
const stFaixa     = dentroFaixa ? 'S' : 'N';

let obs = null;
if (portaAberta) obs = `ALERTA: Porta Aberta | LDR_ADC=${ldrADC}`;
if (!dentroFaixa) {
    const extra = temp < 2 ? `TEMP_FORA_FAIXA: ABAIXO_MINIMO | Desvio=${(temp-2).toFixed(1)}°C`
                           : `TEMP_FORA_FAIXA: ACIMA_MAXIMO | Desvio=${(temp-8).toFixed(1)}°C`;
    obs = obs ? `${obs} | ${extra}` : extra;
}
if (obs) obs = obs.substring(0,200);

const msgLeitura = {
    topic: 'INSERT INTO LEITURA_TEMPERATURA (ID_DISPOSITIVO,NR_TEMPERATURA,NR_UMIDADE,DT_LEITURA,ST_DENTRO_FAIXA,DS_OBSERVACAO) VALUES (?,?,?,NOW(),?,?)',
    payload: [esp32.id_dispositivo||1, temp, isNaN(umid)?null:umid, stFaixa, obs]
};

const flowCtx = flow.get('alertaAtivo')||{fora_faixa:false,porta_aberta:false};
const novoAlerta = (!dentroFaixa&&!flowCtx.fora_faixa)||(portaAberta&&!flowCtx.porta_aberta);
flow.set('alertaAtivo',{fora_faixa:!dentroFaixa,porta_aberta:portaAberta});

let msgAlerta = null;
if (novoAlerta) {
    const tipo = temp > 8 ? 'TEMP_ALTA' : (temp < 2 ? 'TEMP_BAIXA' : 'TEMP_ALTA');
    const sev  = temp > 20 || temp < -2 ? 'CRITICA' : temp > 12 || temp < 0 ? 'ALTA' : 'MEDIA';
    msgAlerta = {
        topic: 'INSERT INTO ALERTA_TEMPERATURA (ID_DISPOSITIVO,DS_TIPO_ALERTA,DS_SEVERIDADE,NR_TEMP_REGISTRADA,DT_INICIO,DS_MENSAGEM,ST_RESOLVIDO) VALUES (?,?,?,?,NOW(),?,\'N\')',
        payload: [esp32.id_dispositivo||1, tipo, sev, temp,
            `[KURA IoT] Temp: ${temp}°C. Faixa: 2-8°C. Porta: ${portaAberta?'ABERTA':'FECHADA'}.`.substring(0,500)]
    };
}

const msgDash = { payload: { temperatura:temp, umidade:umid, porta_aberta:portaAberta,
    dentro_faixa:dentroFaixa, status: dentroFaixa&&!portaAberta?'NORMAL':'ALERTA',
    clima: clima&&clima.main ? { temp_ext:clima.main.temp, descricao:clima.weather?.[0]?.description } : {},
    ts: new Date().toLocaleString('pt-BR',{timeZone:'America/Sao_Paulo'}) } };

return [msgLeitura, msgAlerta, msgDash];

// Quando o ESP32 cai abruptamente, o broker publica o LWT
// com status='offline'. Geramos um alerta SENSOR_OFFLINE no banco.
const status = msg.payload;
if (status && status.status === 'offline') {
    msg.topic = 'INSERT INTO ALERTA_TEMPERATURA (ID_DISPOSITIVO,DS_TIPO_ALERTA,DS_SEVERIDADE,NR_TEMP_REGISTRADA,DT_INICIO,DS_MENSAGEM,ST_RESOLVIDO) VALUES (?,?,?,NULL,NOW(),?,\'N\')';
    msg.payload = [
        1,                   // ID_DISPOSITIVO
        'SENSOR_OFFLINE',    // DS_TIPO_ALERTA
        'CRITICA',           // DS_SEVERIDADE
        '[KURA IoT] Dispositivo ESP32 câmara fria ficou OFFLINE. Verificar conexão imediatamente.'
    ];
    return msg;
}
return null; // online: não faz nada
